// ExecutePricingScript executes a user-provided Lua script to calculate the final price
// of a product based on the given context.
func ExecutePricingScript(script string, ctx map[string]float64) (float64, error) {
	// Create a new Lua state
	L := lua.NewState()
	defer L.Close()

	// Load and execute the script to define the calculate_final_price function
	if err := L.DoString(script); err != nil {
		return 0, fmt.Errorf("failed to load Lua script: %w", err)
	}

	// Retrieve the calculate_final_price function from the global environment
	fn := L.GetGlobal("calculate_final_price")
	if fn.Type() != lua.LTFunction {
		return 0, fmt.Errorf("calculate_final_price is not a valid function (got type %s)", fn.Type().String())
	}

	// Convert Go context map to a Lua table
	ctxTable := L.NewTable()
	for k, v := range ctx {
		L.SetField(ctxTable, k, lua.LNumber(v))
	}

	// Call the function with protected mode to catch runtime errors
	if err := L.CallByParam(lua.P{
		Fn:      fn,
		NRet:    1,
		Protect: true,
	}, ctxTable); err != nil {
		return 0, fmt.Errorf("error executing calculate_final_price: %w", err)
	}

	// Get the return value from the top of the stack
	result := L.Get(-1)
	// Clean up the stack by popping the result
	L.Pop(1)

	// Validate that the result is a number
	if result.Type() != lua.LTNumber {
		return 0, fmt.Errorf("calculate_final_price returned non-number type: %s", result.Type().String())
	}

	return float64(result.(lua.LNumber)), nil
}

