func ExecutePricingScript(script string, ctx map[string]float64) (float64, error) {
	// Create a new Lua state with no preloaded libraries to avoid dangerous defaults
	L := lua.NewState(lua.Options{SkipOpenLibs: true})
	defer L.Close()

	// Open only necessary and safe libraries
	lua.OpenMath(L)    // Safe mathematical functions
	lua.OpenString(L)  // Safe string manipulation functions
	lua.OpenTable(L)   // Safe table manipulation functions
	lua.OpenBase(L)    // Base library (we'll strip dangerous functions below)

