	dangerousGlobals := []string{
		"load", "loadfile", "loadstring", "dofile", "require",
		"collectgarbage", "getfenv", "setfenv",
		"getmetatable", "setmetatable",
	}
	for _, name := range dangerousGlobals {
		L.SetGlobal(name, lua.LNil)
	}

	// Set up a timeout to prevent long-running scripts from hanging
	execCtx, cancel := context.WithTimeout(context.Background(), 1*time.Second)
	defer cancel()
	L.SetContext(execCtx)

	// Load and execute the user script (defines the calculate_final_price function)
	if err := L.DoString(script); err != nil {
		return 0, fmt.Errorf("failed to load Lua script: %w", err)
	}

	// Retrieve the calculate_final_price function from the global environment
	calcFn := L.GetGlobal("calculate_final_price")
