	for key, value := range ctx {
		L.SetField(luaCtxTable, key, lua.LNumber(value))
	}

	// Call the calculate_final_price function with the context table
	if err := L.CallByParam(lua.P{
		Fn:      calcFn,
		NRet:    1,
		Protect: true, // Ensure errors are returned instead of panicking
	}, luaCtxTable); err != nil {
