		default:
			// Continue execution if timeout not reached
		}
	}, debug.MaskCount, 1000)

	// Load and execute the user script in protected mode
	// No standard libraries are available,  script can't access dangerous features
	if err := L.DoString(script); err != nil {
		return 0, fmt.Errorf("failed to load Lua script: %w", err)
	}

	// Retrieve the required global function
	fn := L.GetGlobal("calculate_final_price")
	if fn.Type() != lua.LTFunction {
		return 0, fmt.Errorf("calculate_final_price is not a valid function or not defined")
	}

	// Convert Go context map to a Lua table
	innerCtxTable := L.NewTable()
	for k, v := range ctx {
		L.SetField(innerCtxTable, k, lua.LNumber(v))
	}

