func ExecutePricingScript(script string, ctx map[string]float64) (float64, error) {
	// Initialize Lua VM
	L := lua.NewState()
	defer L.Close()

	// Load and execute the user script to define the pricing function
	if err := L.DoString(script); err != nil {
		return 0, err
	}

	// Retrieve the calculate_final_price function from globals
	L.GetGlobal("calculate_final_price")
	if L.Get(-1).Type() != lua.LTFunction {
		return 0, errors.New("global `calculate_final_price` is not a function")
	}

	// Create and populate the context table
	L.NewTable()
	tbl := L.ToTable(-1)
	for key, value := range ctx {
		tbl.RawSetString(key, lua.LNumber(value))
	}

	// Call the function with 1 argument, expecting 1 return value
	if err := L.PCall(1, 1, nil); err != nil {
		return 0, err
	}

	// Validate the return value type
	if L.Get(-1).Type() != lua.LTNumber {
		return 0, errors.New("`calculate_final_price` did not return a number")
	}

	// Extract and return the floating-point result
	return float64(L.ToNumber(-1)), nil
}

